let output = [];

for (const item of items) {
  const blocks = item.json.text_blocks || [];
  // Consolidated all snippets into one text block for the AI to analyze together
  let consolidatedContent = blocks.map(b => b.snippet).filter(s => s).join("\n\n---\n\n");

  output.push({
    json: {
      ...item.json, // PRESERVE ALL LEAD DATA
      consolidated_snippets: consolidatedContent || "No specific snippets found.",
      source: "Google AI Mode"
    }
  });
}

return output;

