let text = $json.content;

// remove markdown if AI adds ```json
text = text.replace(/```json/g, '').replace(/```/g, '').trim();

let parsed = {};

try {
  parsed = JSON.parse(text);
} catch (e) {
  parsed = {
    intent_signal: "unknown",
    summary: "Parsing failed",
    opportunity: "N/A"
  };
}

return {
  json: {
    ...$json,
    intent_signal: parsed.intent_signal || "unknown",
    summary: parsed.summary || "Could not analyze snippet",
    opportunity: parsed.opportunity || "Manual review recommended"
  }
};

let output = [];

for (const item of items) {

  let text = item.json.content || item.json || "";

  // convert object to string if needed
  if (typeof text !== "string") {
    text = JSON.stringify(text);
  }

  // remove markdown if present
  text = text.replace(/```json/g, '').replace(/```/g, '').trim();

  // fix escaped new lines and quotes
  text = text.replace(/\\n/g, " ").replace(/\\"/g, '"');

  let parsed = {};

  try {
    parsed = JSON.parse(text);
  } catch (err) {
    parsed = { 
      subject: "Meeting Request: Miraee Agentic OS",
      email_body: "Hi, I tried to reach out but had an issue generating the personalized message. I'd love to show you how Miraee can simplify your travel and expenses."
    };
  }

  output.push({
    json: {
      ...item.json, // PRESERVE ALL ORIGINAL DATA (including row_number)
      name: parsed.name || item.json.name || item.json.Name || "",
      subject: parsed.subject || "",
      email_body: parsed.email_body || ""
    }
  });

}

return output;
